const body = $input.item.json;
const entry = body.entry?.[0];
const change = entry?.changes?.[0];
const message = change?.value?.messages?.[0];
let from, text;
if (message) {
  from = message.from;
  text = (message.text?.body || '').toLowerCase().trim();
} else {
  from = body.from || body.From || '';
  text = (body.text?.body || body.Body || '').toLowerCase().trim();
}
return [{ json: { from, text, timestamp: Date.now() } }];

const { from, text } = $input.item.json;

const MENU = `☕ *MONTE CAFÉ ARBOLEDAS*

¡Bienvenido! ¿Qué necesitas?

1️⃣ Ver menú y precios
2️⃣ Hacer pedido
3️⃣ Horarios
4️⃣ Ubicación

_Responde con el número_`;

const MENU_ITEMS = `☕ *MENÚ MONTE CAFÉ*

🥐 Desayuno completo — *$95*
   Café + pan + proteína

🔥 Bebida caliente — *$45*
   Café, té, chocolate, etc

🥤 Malteada — *$65*
   Sabores variados

📦 Orden para llevar — *Envío gratis*
   Desayunos y bebidas

👉 _Para ordenar:_
https://wa.me/525532652927`;

const PEDIR = `📦 *HACER PEDIDO EN MONTE CAFÉ*

Escríbenos qué quieres:
👉 https://wa.me/525532652927

_Dinos:_
☕ Qué quieres pedir
📍 Entrega o para llevar
📞 Tu teléfono

⚡ _Preparamos en minutos_
🚚 _Envío gratis en Arboledas_`;

const HORARIOS = `⏰ *HORARIOS MONTE CAFÉ*

🗓️ Lunes a Domingo: *7AM — 8PM*

✅ Abierto todos los días

📍 Calzada de los Jinetes 77
Las Arboledas

_Tu café favorito te espera_ ☕`;

const UBICACION = `📍 *CÓMO LLEGAR*

*Monte Café Arboledas*
Calzada de los Jinetes 77
Las Arboledas, Tlalnepantla de Baz

🗺️ https://maps.google.com/maps?q=Monte+Cafe+Jinetes+77

📞 Llámanos para pedidos rápidos

_Estamos entre Jinetes y el Paradero_ 📌`;

const saludos = ['hola','hi','hello','buenas','buenos','buen','inicio','menu','start','0'];
let msg;
if (saludos.some(s => text.startsWith(s)) || text === '') {
  msg = MENU;
} else if (text === '1' || text.includes('menu') || text.includes('menú') || text.includes('precio') || text.includes('café')) {
  msg = MENU_ITEMS;
} else if (text === '2' || text.includes('pedir') || text.includes('orden') || text.includes('pedido')) {
  msg = PEDIR;
} else if (text === '3' || text.includes('horario') || text.includes('abierto') || text.includes('cierra')) {
  msg = HORARIOS;
} else if (text === '4' || text.includes('ubicac') || text.includes('direcc') || text.includes('donde') || text.includes('llegar')) {
  msg = UBICACION;
} else if (text.includes('desayun') || text.includes('bebida') || text.includes('malteada') || text.includes('café')) {
  msg = MENU_ITEMS;
} else {
  msg = MENU;
}

return [{ json: { from, mensaje_respuesta: msg } }];
